// @ts-nocheck
import React, { useState, useEffect, useMemo } from "react";
import {
  Wallet,
  TrendingUp,
  CreditCard,
  Target,
  Calculator,
  PieChart as PieIcon,
  Building2,
  Coins,
  Shield,
  Briefcase,
  Plus,
  Trash2,
  Download,
  Upload,
  ArrowUpRight,
  ArrowDownRight,
  IndianRupee,
  Calendar,
  AlertCircle,
  X,
  Edit3,
  FileText,
  Landmark,
  BarChart3,
  Layers,
  Receipt,
  Repeat,
  HandCoins,
  Banknote,
  LineChart as LineIcon,
  Sparkles,
} from "lucide-react";
import {
  LineChart,
  Line,
  AreaChart,
  Area,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";

// ================== DESIGN TOKENS ==================
// Aesthetic: Editorial/financial-journal — deep navy + parchment cream + ledger-red accent
// Inspired by old-world bank ledgers meets modern analytics terminal
const THEME = {
  ink: "#0A1628", // deep navy
  paper: "#F5EFE3", // parchment cream
  accent: "#B5322C", // ledger red
  gold: "#C9A961", // muted gold
  sage: "#6B8E6F", // sage green (gains)
  rust: "#A64B2A", // rust (losses)
  muted: "#8B7D6B", // taupe
  line: "#D4C9B4", // divider
  darkInk: "#061020",
};

const PIE_COLORS = [
  "#0A1628",
  "#B5322C",
  "#C9A961",
  "#6B8E6F",
  "#A64B2A",
  "#8B7D6B",
  "#4A5D73",
  "#8B4C6B",
];

// ================== HELPERS ==================
const fmtINR = (n) => {
  if (n === null || n === undefined || isNaN(n)) return "₹0";
  const abs = Math.abs(n);
  const sign = n < 0 ? "-" : "";
  if (abs >= 10000000) return `${sign}₹${(abs / 10000000).toFixed(2)}Cr`;
  if (abs >= 100000) return `${sign}₹${(abs / 100000).toFixed(2)}L`;
  if (abs >= 1000) return `${sign}₹${(abs / 1000).toFixed(1)}K`;
  return `${sign}₹${abs.toFixed(0)}`;
};
const fmtINRFull = (n) => {
  if (n === null || n === undefined || isNaN(n)) return "₹0";
  return `₹${Number(n).toLocaleString("en-IN", { maximumFractionDigits: 0 })}`;
};
const uid = () =>
  Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
const today = () => new Date().toISOString().slice(0, 10);
const monthsBetween = (d1, d2) => {
  const a = new Date(d1),
    b = new Date(d2);
  return (
    (b.getFullYear() - a.getFullYear()) * 12 + (b.getMonth() - a.getMonth())
  );
};

// Compound interest for FD/RD/Bond maturity estimates
const fdMaturity = (principal, rate, years, freq = 4) => {
  return principal * Math.pow(1 + rate / 100 / freq, freq * years);
};
const rdMaturity = (monthly, rate, months) => {
  // RD quarterly compounding approximation
  const n = 4,
    r = rate / 100;
  let total = 0;
  for (let i = 0; i < months; i++) {
    const t = (months - i) / 12;
    total += monthly * Math.pow(1 + r / n, n * t);
  }
  return total;
};

// ================== TAX CALCULATORS (FY 2025-26) ==================
const calcTaxNew = (income) => {
  // New regime FY 25-26 slabs (post Budget 2025)
  let tax = 0;
  const slabs = [
    [400000, 0],
    [800000, 0.05],
    [1200000, 0.1],
    [1600000, 0.15],
    [2000000, 0.2],
    [2400000, 0.25],
    [Infinity, 0.3],
  ];
  let prev = 0;
  for (const [limit, rate] of slabs) {
    if (income > prev) {
      tax += (Math.min(income, limit) - prev) * rate;
      prev = limit;
    } else break;
  }
  // Rebate 87A up to 12L under new regime
  if (income <= 1200000) tax = 0;
  const cess = tax * 0.04;
  return { tax, cess, total: tax + cess };
};

const calcTaxOld = (income, deductions = 0) => {
  const taxable = Math.max(0, income - deductions);
  let tax = 0;
  const slabs = [
    [250000, 0],
    [500000, 0.05],
    [1000000, 0.2],
    [Infinity, 0.3],
  ];
  let prev = 0;
  for (const [limit, rate] of slabs) {
    if (taxable > prev) {
      tax += (Math.min(taxable, limit) - prev) * rate;
      prev = limit;
    } else break;
  }
  if (taxable <= 500000) tax = 0; // 87A old regime
  const cess = tax * 0.04;
  return { tax, cess, total: tax + cess, taxable };
};

// ================== STORAGE ==================
const STORAGE_KEY = "finance_dashboard_v1";
const loadState = () => {
  try {
    const raw = window.storage ? null : null; // window.storage is async; handled in effect
    return null;
  } catch {
    return null;
  }
};

const DEFAULT_STATE = {
  profile: { name: "", fy: "2025-26", regime: "new" },
  bankAccounts: [],
  transactions: [],
  fixedDeposits: [],
  recurringDeposits: [],
  bonds: [],
  ppf: [],
  nps: [],
  lic: [],
  termPlans: [],
  mutualFunds: [],
  stocks: [],
  demat: [],
  creditCards: [],
  prepaidCards: [],
  loansTaken: [],
  loansGiven: [],
  subscriptions: [],
  goals: [],
  income: [],
  taxPayments: [],
};

// ================== MAIN APP ==================
export default function FinanceDashboard() {
  const [state, setState] = useState(DEFAULT_STATE);
  const [loaded, setLoaded] = useState(false);
  const [tab, setTab] = useState("overview");
  const [modal, setModal] = useState(null);

  // Inject Google Fonts once
  useEffect(() => {
    if (document.getElementById("finance-dash-fonts")) return;
    const link = document.createElement("link");
    link.id = "finance-dash-fonts";
    link.rel = "stylesheet";
    link.href =
      "https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;800;900&family=EB+Garamond:ital,wght@0,400;0,500;0,600;0,700;1,400&display=swap";
    document.head.appendChild(link);
  }, []);

  // Load from persistent storage on mount
  useEffect(() => {
    (async () => {
      try {
        if (window.storage) {
          const result = await window.storage.get(STORAGE_KEY);
          if (result && result.value) {
            const parsed = JSON.parse(result.value);
            setState({ ...DEFAULT_STATE, ...parsed });
          }
        }
      } catch (e) {
        /* no data yet */
      }
      setLoaded(true);
    })();
  }, []);

  // Save on change
  useEffect(() => {
    if (!loaded) return;
    (async () => {
      try {
        if (window.storage) {
          await window.storage.set(STORAGE_KEY, JSON.stringify(state));
        }
      } catch (e) {
        console.error("save failed", e);
      }
    })();
  }, [state, loaded]);

  // ================== COMPUTED FINANCIAL METRICS ==================
  const metrics = useMemo(() => {
    const cashInBanks = state.bankAccounts.reduce(
      (s, a) => s + Number(a.balance || 0),
      0
    );
    const fdValue = state.fixedDeposits.reduce(
      (s, f) => s + Number(f.principal || 0),
      0
    );
    const rdValue = state.recurringDeposits.reduce((s, r) => {
      const m = monthsBetween(r.startDate, today());
      return (
        s + Math.min(m, Number(r.tenureMonths || 0)) * Number(r.monthly || 0)
      );
    }, 0);
    const bondValue = state.bonds.reduce(
      (s, b) => s + Number(b.faceValue || 0),
      0
    );
    const ppfValue = state.ppf.reduce((s, p) => s + Number(p.balance || 0), 0);
    const npsValue = state.nps.reduce((s, n) => s + Number(n.balance || 0), 0);
    const licValue = state.lic.reduce(
      (s, l) => s + Number(l.premiumPaid || 0),
      0
    );
    const mfValue = state.mutualFunds.reduce(
      (s, m) => s + Number(m.units || 0) * Number(m.currentNav || 0),
      0
    );
    const mfInvested = state.mutualFunds.reduce(
      (s, m) => s + Number(m.invested || 0),
      0
    );
    const stockValue = state.stocks.reduce(
      (s, st) => s + Number(st.qty || 0) * Number(st.currentPrice || 0),
      0
    );
    const stockInvested = state.stocks.reduce(
      (s, st) => s + Number(st.qty || 0) * Number(st.avgPrice || 0),
      0
    );

    const loansGivenValue = state.loansGiven.reduce(
      (s, l) => s + Number(l.outstanding || 0),
      0
    );
    const prepaidValue = state.prepaidCards.reduce(
      (s, p) => s + Number(p.balance || 0),
      0
    );

    const ccOutstanding = state.creditCards.reduce(
      (s, c) => s + Number(c.outstanding || 0),
      0
    );
    const loansTakenValue = state.loansTaken.reduce(
      (s, l) => s + Number(l.outstanding || 0),
      0
    );

    const totalAssets =
      cashInBanks +
      fdValue +
      rdValue +
      bondValue +
      ppfValue +
      npsValue +
      licValue +
      mfValue +
      stockValue +
      loansGivenValue +
      prepaidValue;
    const totalLiabilities = ccOutstanding + loansTakenValue;
    const netWorth = totalAssets - totalLiabilities;

    // Income/Expense current month
    const now = new Date();
    const ym = now.toISOString().slice(0, 7);
    const monthTxns = state.transactions.filter(
      (t) => t.date && t.date.startsWith(ym)
    );
    const monthIncome = monthTxns
      .filter((t) => t.type === "credit")
      .reduce((s, t) => s + Number(t.amount || 0), 0);
    const monthExpense = monthTxns
      .filter((t) => t.type === "debit")
      .reduce((s, t) => s + Number(t.amount || 0), 0);

    // Annual income from income ledger
    const fyStart = new Date(`${state.profile.fy.split("-")[0]}-04-01`);
    const annualIncome = state.income
      .filter((i) => new Date(i.date) >= fyStart)
      .reduce((s, i) => s + Number(i.amount || 0), 0);

    const subTotal = state.subscriptions.reduce((s, sub) => {
      const m =
        sub.cycle === "yearly"
          ? Number(sub.amount || 0) / 12
          : sub.cycle === "quarterly"
          ? Number(sub.amount || 0) / 3
          : Number(sub.amount || 0);
      return s + m;
    }, 0);

    return {
      cashInBanks,
      fdValue,
      rdValue,
      bondValue,
      ppfValue,
      npsValue,
      licValue,
      mfValue,
      mfInvested,
      stockValue,
      stockInvested,
      ccOutstanding,
      loansTakenValue,
      loansGivenValue,
      prepaidValue,
      totalAssets,
      totalLiabilities,
      netWorth,
      monthIncome,
      monthExpense,
      annualIncome,
      subTotal,
      mfPnL: mfValue - mfInvested,
      stockPnL: stockValue - stockInvested,
    };
  }, [state]);

  const assetBreakdown = useMemo(
    () =>
      [
        { name: "Bank Cash", value: metrics.cashInBanks },
        { name: "Fixed Deposits", value: metrics.fdValue },
        { name: "Recurring Deposits", value: metrics.rdValue },
        { name: "Mutual Funds", value: metrics.mfValue },
        { name: "Stocks", value: metrics.stockValue },
        { name: "PPF", value: metrics.ppfValue },
        { name: "NPS", value: metrics.npsValue },
        { name: "Bonds", value: metrics.bondValue },
        { name: "LIC", value: metrics.licValue },
        { name: "Loans Given", value: metrics.loansGivenValue },
      ].filter((x) => x.value > 0),
    [metrics]
  );

  // Monthly trend for last 12 months
  const trendData = useMemo(() => {
    const arr = [];
    const now = new Date();
    for (let i = 11; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const ym = d.toISOString().slice(0, 7);
      const label = d.toLocaleString("en-IN", { month: "short" });
      const txns = state.transactions.filter(
        (t) => t.date && t.date.startsWith(ym)
      );
      const inc = txns
        .filter((t) => t.type === "credit")
        .reduce((s, t) => s + Number(t.amount || 0), 0);
      const exp = txns
        .filter((t) => t.type === "debit")
        .reduce((s, t) => s + Number(t.amount || 0), 0);
      arr.push({ month: label, income: inc, expense: exp, net: inc - exp });
    }
    return arr;
  }, [state.transactions]);

  // ================== CRUD ==================
  const addItem = (key, item) =>
    setState((s) => ({ ...s, [key]: [...s[key], { id: uid(), ...item }] }));
  const removeItem = (key, id) =>
    setState((s) => ({ ...s, [key]: s[key].filter((x) => x.id !== id) }));
  const updateItem = (key, id, patch) =>
    setState((s) => ({
      ...s,
      [key]: s[key].map((x) => (x.id === id ? { ...x, ...patch } : x)),
    }));

  // ================== EXPORT / IMPORT ==================
  const exportJSON = () => {
    const blob = new Blob([JSON.stringify(state, null, 2)], {
      type: "application/json",
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `finance-backup-${today()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };
  const importJSON = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const parsed = JSON.parse(ev.target.result);
        setState({ ...DEFAULT_STATE, ...parsed });
        alert("Backup restored successfully");
      } catch {
        alert("Invalid backup file");
      }
    };
    reader.readAsText(file);
  };

  const resetAll = () => {
    if (confirm("Delete ALL data? This cannot be undone."))
      setState(DEFAULT_STATE);
  };

  // ================== TABS ==================
  const tabs = [
    { id: "overview", label: "Ledger", icon: LineIcon },
    { id: "banks", label: "Banks", icon: Landmark },
    { id: "investments", label: "Investments", icon: TrendingUp },
    { id: "demat", label: "Demat & Stocks", icon: BarChart3 },
    { id: "credit", label: "Credit & Loans", icon: CreditCard },
    { id: "subs", label: "Subscriptions", icon: Repeat },
    { id: "goals", label: "Goals", icon: Target },
    { id: "tax", label: "Tax Vault", icon: Calculator },
  ];

  if (!loaded) {
    return (
      <div
        style={{
          minHeight: "100vh",
          background: THEME.paper,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontFamily: "'Cormorant Garamond', serif",
          color: THEME.ink,
        }}
      >
        Loading ledger…
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: `radial-gradient(ellipse at top, ${THEME.paper} 0%, #ECE3D0 100%)`,
        fontFamily: "'EB Garamond', 'Cormorant Garamond', Georgia, serif",
        color: THEME.ink,
        position: "relative",
      }}
    >
      {/* Grain texture overlay */}
      <div
        style={{
          position: "fixed",
          inset: 0,
          pointerEvents: "none",
          opacity: 0.04,
          zIndex: 0,
          backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='2'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E")`,
        }}
      />

      {/* HEADER */}
      <header
        style={{
          borderBottom: `2px solid ${THEME.ink}`,
          background: THEME.paper,
          position: "sticky",
          top: 0,
          zIndex: 40,
          boxShadow: "0 1px 0 rgba(10,22,40,0.1)",
        }}
      >
        <div
          style={{
            maxWidth: 1400,
            margin: "0 auto",
            padding: "20px 32px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            flexWrap: "wrap",
            gap: 16,
          }}
        >
          <div>
            <div
              style={{
                fontSize: 11,
                letterSpacing: "0.3em",
                color: THEME.muted,
                textTransform: "uppercase",
                marginBottom: 4,
              }}
            >
              Private Financial Ledger · FY {state.profile.fy}
            </div>
            <h1
              style={{
                fontFamily: "'Playfair Display', 'EB Garamond', serif",
                fontSize: 38,
                fontWeight: 900,
                margin: 0,
                letterSpacing: "-0.02em",
                color: THEME.ink,
                lineHeight: 1,
              }}
            >
              The Counting House
            </h1>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <button onClick={exportJSON} style={btnGhost}>
              <Download size={14} /> Export
            </button>
            <label style={btnGhost}>
              <Upload size={14} /> Import
              <input
                type="file"
                accept=".json"
                onChange={importJSON}
                style={{ display: "none" }}
              />
            </label>
            <button
              onClick={resetAll}
              style={{
                ...btnGhost,
                color: THEME.accent,
                borderColor: THEME.accent,
              }}
            >
              <Trash2 size={14} /> Reset
            </button>
          </div>
        </div>

        {/* TAB NAV */}
        <nav
          style={{
            maxWidth: 1400,
            margin: "0 auto",
            padding: "0 32px",
            display: "flex",
            gap: 0,
            overflowX: "auto",
            borderTop: `1px solid ${THEME.line}`,
          }}
        >
          {tabs.map((t) => {
            const Icon = t.icon;
            const active = tab === t.id;
            return (
              <button
                key={t.id}
                onClick={() => setTab(t.id)}
                style={{
                  background: "transparent",
                  border: "none",
                  cursor: "pointer",
                  padding: "14px 20px",
                  fontFamily: "inherit",
                  fontSize: 13,
                  letterSpacing: "0.08em",
                  textTransform: "uppercase",
                  color: active ? THEME.accent : THEME.ink,
                  borderBottom: `3px solid ${
                    active ? THEME.accent : "transparent"
                  }`,
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  whiteSpace: "nowrap",
                  fontWeight: active ? 700 : 500,
                  transition: "all 0.2s",
                }}
              >
                <Icon size={14} /> {t.label}
              </button>
            );
          })}
        </nav>
      </header>

      <main
        style={{
          maxWidth: 1400,
          margin: "0 auto",
          padding: "32px",
          position: "relative",
          zIndex: 1,
        }}
      >
        {tab === "overview" && (
          <Overview
            metrics={metrics}
            state={state}
            assetBreakdown={assetBreakdown}
            trendData={trendData}
          />
        )}
        {tab === "banks" && (
          <BanksTab
            state={state}
            addItem={addItem}
            removeItem={removeItem}
            updateItem={updateItem}
          />
        )}
        {tab === "investments" && (
          <InvestmentsTab
            state={state}
            addItem={addItem}
            removeItem={removeItem}
          />
        )}
        {tab === "demat" && (
          <DematTab state={state} addItem={addItem} removeItem={removeItem} />
        )}
        {tab === "credit" && (
          <CreditTab state={state} addItem={addItem} removeItem={removeItem} />
        )}
        {tab === "subs" && (
          <SubsTab
            state={state}
            addItem={addItem}
            removeItem={removeItem}
            metrics={metrics}
          />
        )}
        {tab === "goals" && (
          <GoalsTab
            state={state}
            addItem={addItem}
            removeItem={removeItem}
            metrics={metrics}
          />
        )}
        {tab === "tax" && (
          <TaxTab
            state={state}
            addItem={addItem}
            removeItem={removeItem}
            metrics={metrics}
            setState={setState}
          />
        )}
      </main>

      <footer
        style={{
          textAlign: "center",
          padding: "40px 20px",
          color: THEME.muted,
          fontSize: 12,
          letterSpacing: "0.1em",
          borderTop: `1px solid ${THEME.line}`,
          marginTop: 40,
        }}
      >
        — Kept in the old manner · Data stored locally on your device —
      </footer>
    </div>
  );
}

