      }}
    >
      <Trash2 size={14} />
    </button>
    {children}
  </div>
);

const Grid = ({ children }) => (
  <div
    style={{
      display: "grid",
      gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
      gap: 16,
    }}
  >
    {children}
  </div>
);

function FDList({ items, onRemove }) {
  if (!items.length) return <EmptyHint text="No fixed deposits yet" />;
  return (
    <Grid>
      {items.map((f) => {
        const maturity = fdMaturity(
          Number(f.principal),
          Number(f.rate),
          Number(f.years)
        );
        return (
          <InvestCard key={f.id} onRemove={() => onRemove(f.id)}>
            <div
              style={{
                fontSize: 10,
                letterSpacing: "0.2em",
                textTransform: "uppercase",
                color: THEME.muted,
              }}
            >
              {f.bank}
            </div>
            <div
              style={{
                fontFamily: "'Playfair Display', serif",
                fontSize: 24,
                fontWeight: 800,
                marginTop: 4,
              }}
            >
              {fmtINRFull(f.principal)}
            </div>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 8,
                marginTop: 16,
                fontSize: 12,
              }}
            >
              <Stat k="Rate" v={`${f.rate}%`} />
              <Stat k="Tenure" v={`${f.years} yrs`} />
              <Stat k="Maturity" v={fmtINR(maturity)} />
              <Stat k="Matures on" v={f.maturityDate || "—"} />
            </div>
          </InvestCard>
        );
      })}
    </Grid>
  );
}
const Stat = ({ k, v }) => (
  <div>
    <div
      style={{
        fontSize: 10,
        color: THEME.muted,
        letterSpacing: "0.1em",
        textTransform: "uppercase",
      }}
    >
      {k}
    </div>
    <div style={{ fontWeight: 600, fontSize: 14 }}>{v}</div>
  </div>
);

function RDList({ items, onRemove }) {
  if (!items.length) return <EmptyHint text="No RDs yet" />;
  return (
    <Grid>
      {items.map((r) => {
        const m = Math.min(
          monthsBetween(r.startDate, today()),
          Number(r.tenureMonths)
        );
        const paid = m * Number(r.monthly);
        const maturity = rdMaturity(
          Number(r.monthly),
          Number(r.rate),
          Number(r.tenureMonths)
        );
        return (
          <InvestCard key={r.id} onRemove={() => onRemove(r.id)}>
            <div
              style={{
                fontSize: 10,
                letterSpacing: "0.2em",
                textTransform: "uppercase",
                color: THEME.muted,
              }}
            >
              {r.bank}
            </div>
            <div
              style={{
                fontFamily: "'Playfair Display', serif",
                fontSize: 24,
                fontWeight: 800,
                marginTop: 4,
              }}
            >
              {fmtINRFull(r.monthly)}/mo
            </div>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 8,
                marginTop: 16,
                fontSize: 12,
              }}
            >
