            {regime === "new" && (
              <span
                style={{
                  fontSize: 10,
                  padding: "2px 8px",
                  background: THEME.accent,
                  color: THEME.paper,
                  letterSpacing: "0.15em",
                }}
              >
                SELECTED
              </span>
