              <div
                style={{
                  borderTop: `2px solid ${THEME.ink}`,
                  padding: "10px 0 0",
                  marginTop: 6,
                  display: "flex",
                  justifyContent: "space-between",
                  fontWeight: 700,
                }}
              >
                <span>Total FY</span>
                <span style={{ color: THEME.sage }}>{fmtINRFull(income)}</span>
              </div>
            </div>
          )}
        </div>

        <div style={card}>
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              marginBottom: 16,
            }}
          >
            <div
              style={{
                fontFamily: "'Playfair Display', serif",
                fontSize: 18,
                fontWeight: 700,
              }}
            >
              Tax Payments
            </div>
            <button style={btnGhost} onClick={() => setShowTaxPmt(true)}>
              <Plus size={12} />
            </button>
          </div>
          {state.taxPayments.length === 0 ? (
            <EmptyHint text="No advance tax / TDS logged" />
          ) : (
            <div style={{ display: "grid", gap: 6 }}>
              {state.taxPayments.map((t) => (
                <div
                  key={t.id}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    fontSize: 13,
                    padding: "8px 0",
                    borderBottom: `1px dashed ${THEME.line}`,
                  }}
                >
                  <span>
                    <div style={{ fontWeight: 500 }}>{t.type}</div>
                    <div style={{ fontSize: 11, color: THEME.muted }}>
                      {t.date} · {t.challan || ""}
                    </div>
                  </span>
                  <span
                    style={{
                      fontWeight: 600,
                      fontVariantNumeric: "tabular-nums",
                    }}
                  >
                    {fmtINRFull(t.amount)}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Capital gains hint */}
      <div
        style={{ ...card, marginTop: 24, borderLeft: `4px solid ${THEME.ink}` }}
      >
        <div
          style={{
            fontSize: 10,
            letterSpacing: "0.25em",
            textTransform: "uppercase",
            color: THEME.muted,
          }}
        >
          Capital Gains Snapshot
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr 1fr",
            gap: 16,
            marginTop: 12,
          }}
        >
          <Stat k="Unrealized Equity" v={fmtINRFull(unrealizedLTCG)} />
          <Stat
            k="Est. LTCG tax (12.5% above ₹1.25L)"
            v={fmtINR(Math.max(0, unrealizedLTCG - 125000) * 0.125)}
          />
          <Stat k="Realized (track separately)" v="—" />
        </div>
        <div
          style={{
            fontSize: 12,
            color: THEME.muted,
            fontStyle: "italic",
            marginTop: 12,
          }}
        >
          LTCG on listed equity: 12.5% above ₹1.25L exemption (FY 25-26). STCG
          on listed equity: 20%. Log realized gains via transactions for
          accurate reporting.
        </div>
      </div>

      {showIncome && (
        <IncomeModal
          onClose={() => setShowIncome(false)}
          onSave={(v) => {
            addItem("income", v);
            setShowIncome(false);
          }}
        />
      )}
      {showTaxPmt && (
        <TaxPmtModal
          onClose={() => setShowTaxPmt(false)}
          onSave={(v) => {
            addItem("taxPayments", v);
            setShowTaxPmt(false);
          }}
        />
      )}
    </div>
  );
}

function IncomeModal({ onClose, onSave }) {
  const [f, setF] = useState({
    source: "",
    category: "Salary",
    amount: "",
    date: today(),
  });
  return (
    <Modal title="Log Income" onClose={onClose}>
      <Field label="Source">
        <input
          style={input}
          value={f.source}
          onChange={(e) => setF({ ...f, source: e.target.value })}
          placeholder="Employer / Client name"
        />
      </Field>
      <Field label="Category">
        <select
          style={input}
          value={f.category}
          onChange={(e) => setF({ ...f, category: e.target.value })}
        >
          <option>Salary</option>
          <option>Freelance</option>
          <option>Business</option>
          <option>Interest</option>
          <option>Dividend</option>
          <option>Rental</option>
          <option>Capital Gains</option>
          <option>Other</option>
        </select>
      </Field>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <Field label="Amount">
          <input
            style={input}
            type="number"
            value={f.amount}
            onChange={(e) => setF({ ...f, amount: e.target.value })}
          />
        </Field>
        <Field label="Date">
          <input
            style={input}
            type="date"
            value={f.date}
            onChange={(e) => setF({ ...f, date: e.target.value })}
          />
        </Field>
      </div>
      <ModalActions
        onSave={() => f.source && f.amount && onSave(f)}
        onClose={onClose}
      />
    </Modal>
  );
}

function TaxPmtModal({ onClose, onSave }) {
  const [f, setF] = useState({
    type: "Advance Tax",
    amount: "",
    date: today(),
    challan: "",
  });
  return (
    <Modal title="Log Tax Payment" onClose={onClose}>
      <Field label="Type">
        <select
          style={input}
          value={f.type}
          onChange={(e) => setF({ ...f, type: e.target.value })}
        >
          <option>Advance Tax</option>
          <option>TDS</option>
          <option>Self-Assessment</option>
          <option>TCS</option>
        </select>
      </Field>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
        <Field label="Amount">
          <input
            style={input}
            type="number"
            value={f.amount}
            onChange={(e) => setF({ ...f, amount: e.target.value })}
          />
        </Field>
        <Field label="Date">
          <input
            style={input}
            type="date"
            value={f.date}
            onChange={(e) => setF({ ...f, date: e.target.value })}
          />
        </Field>
      </div>
      <Field label="Challan Number (optional)">
        <input
          style={input}
          value={f.challan}
          onChange={(e) => setF({ ...f, challan: e.target.value })}
        />
      </Field>
      <ModalActions onSave={() => f.amount && onSave(f)} onClose={onClose} />
    </Modal>
  );
}

// ================== MODAL SHELL ==================
function Modal({ title, children, onClose }) {
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(10,22,40,0.6)",
        zIndex: 100,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 20,
        backdropFilter: "blur(4px)",
      }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: THEME.paper,
          width: "100%",
          maxWidth: 560,
          maxHeight: "90vh",
          overflowY: "auto",
          border: `2px solid ${THEME.ink}`,
          boxShadow: "0 20px 60px rgba(10,22,40,0.4)",
        }}
      >
        <div
          style={{
            padding: "20px 28px",
            borderBottom: `1px solid ${THEME.line}`,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <div
            style={{
              fontFamily: "'Playfair Display', serif",
              fontSize: 22,
              fontWeight: 800,
            }}
          >
            {title}
          </div>
          <button
            onClick={onClose}
            style={{
              background: "transparent",
              border: "none",
              cursor: "pointer",
              color: THEME.ink,
            }}
          >
            <X size={20} />
          </button>
        </div>
        <div style={{ padding: 28 }}>{children}</div>
      </div>
    </div>
  );
}

const Field = ({ label: lbl, children }) => (
  <div style={{ marginBottom: 14 }}>
    <div style={label}>{lbl}</div>
    {children}
  </div>
);

function ModalActions({ onSave, onClose }) {
  return (
    <div
      style={{
        display: "flex",
        justifyContent: "flex-end",
        gap: 8,
        marginTop: 20,
        paddingTop: 20,
        borderTop: `1px solid ${THEME.line}`,
      }}
    >
      <button style={btnGhost} onClick={onClose}>
        Cancel
      </button>
      <button style={btnAccent} onClick={onSave}>
        Save
      </button>
    </div>
  );
}
